import{_ as t,o as a,c as s,a0 as i}from"./chunks/framework.CWk8AOcY.js";const d=JSON.parse('{"title":"Templates Overview","description":"","frontmatter":{},"headers":[],"relativePath":"guide/templates.md","filePath":"guide/templates.md"}'),o={name:"guide/templates.md"};function l(n,e,r,p,m,c){return a(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="templates-overview" tabindex="-1">Templates Overview <a class="header-anchor" href="#templates-overview" aria-label="Permalink to &quot;Templates Overview&quot;">​</a></h1><p>A Template is the base image and configuration snapshot used to create Cube-Sandbox instances. This page covers the <strong>concept and lifecycle</strong> of templates.</p><ul><li>To create, monitor, query, or delete templates using the CLI, see <a href="./tutorials/template-from-image.html">Creating Templates from OCI Images</a>.</li><li>To inspect template build status and preview the effective request, see <a href="./template-inspection-and-preview.html">Template Inspection and Request Preview</a>.</li></ul><h2 id="template-lifecycle-three-step-process" tabindex="-1">Template Lifecycle (Three-Step Process) <a class="header-anchor" href="#template-lifecycle-three-step-process" aria-label="Permalink to &quot;Template Lifecycle (Three-Step Process)&quot;">​</a></h2><ol><li><p><strong>Init (Initialization Build)</strong> Based on a base image (like Ubuntu) and Dockerfile, use a build engine like Buildkit to package a rootfs filesystem that meets the sandbox runtime requirements.</p></li><li><p><strong>Boot &amp; Snapshot</strong> Cold boot the initialized rootfs inside a MicroVM. Wait for the system and language environment (like Python, Node) to fully load, then take a snapshot of the memory and state at that moment.</p></li><li><p><strong>Deploy (Registration &amp; Publishing)</strong> Register the packaged Rootfs and Snapshot files into the system to become an available Template. Subsequently, this Template can be used to achieve <strong>Hot Start</strong> for sandboxes in the tens-of-milliseconds range.</p></li></ol><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./tutorials/template-from-image.html">Creating Templates from OCI Images</a> — step-by-step CLI guide with probe configuration, progress monitoring, and troubleshooting.</li><li><a href="./template-inspection-and-preview.html">Template Inspection and Request Preview</a> — how to inspect template status and preview the effective request.</li></ul>',7)])])}const u=t(o,[["render",l]]);export{d as __pageData,u as default};
